def parse_kv_pairs(pairs):
    d: Dict[str, Any] = {}
    for p in pairs or []:
        if "=" not in p:
            d[p] = True
            continue
        k, v = p.split("=", 1)
        v = v.strip()
        if v.lower() in ("true", "false"):
            d[k] = v.lower() == "true"
        else:
            try:
                if "." in v:
                    d[k] = float(v)
                else:
                    d[k] = int(v)
            except ValueError:
                d[k] = v
    return d


