    pub.add_argument("--count", type=int, default=1)
    pub.add_argument("--task", action="append", default=[], help="Task field as key=value (repeatable)")
    pub.add_argument("--json", dest="task_json", default=None, help="Task as JSON string")
    pub.add_argument("--persistent", default="true")
